def step1_validate_cart(cart_items: list[CartItem]) -> ValidatedCart:
    """Step 1: Validate cart items - check stock, quantities, prices."""
    if not cart_items:
        raise CartValidationError("Cart is empty.")

    validation_errors = []
    valid_items = []
    subtotal = 0.0

    for item in cart_items:
        item_errors = []

        if item.price < 0:
            item_errors.append(f"Item '{item.name}' has invalid price: {item.price}")

        if item.quantity <= 0:
            item_errors.append(f"Item '{item.name}' has invalid quantity: {item.quantity}")

        if item.quantity > item.max_quantity:
            item_errors.append(
                f"Item '{item.name}' quantity ({item.quantity}) exceeds maximum allowed ({item.max_quantity})"
            )

        if not item.in_stock:
            item_errors.append(f"Item '{item.name}' is out of stock")

        if not item.product_id:
            item_errors.append(f"Item '{item.name}' has no product ID")

        if not item.name or not item.name.strip():
            item_errors.append("Item has no name")

        if item_errors:
            validation_errors.extend(item_errors)
        else:
            valid_items.append(item)
            subtotal += item.price * item.quantity

    if validation_errors and not valid_items:
        raise CartValidationError(
            "All cart items are invalid.",
            {"errors": validation_errors}
        )

    subtotal = round(subtotal, 2)

    validated_cart = ValidatedCart(
        items=valid_items,
        subtotal=subtotal,
        validation_errors=validation_errors,
        is_valid=len(validation_errors) == 0,
    )

    print(f"[Step 1] Cart validated: {len(valid_items)} valid items, subtotal=${subtotal:.2f}")
    if validation_errors:
        print(f"  Warnings: {validation_errors}")

    return validated_cart


def step2_apply_discount(
    validated_cart: ValidatedCart,
    user: User,
    discount_code: Optional[str] = None,
) -> DiscountResult:
    """Step 2: Apply discount codes with user permission validation."""
    subtotal = validated_cart.subtotal

    if not discount_code:
        result = DiscountResult(
            original_subtotal=subtotal,
            discount_amount=0.0,
            discounted_subtotal=subtotal,
            discount_code_applied=None,
            discount_message="No discount code provided.",
        )
        print(f"[Step 2] No discount applied. Subtotal remains ${subtotal:.2f}")
        return result

    code_upper = discount_code.upper().strip()

    # Look up discount code
    discount = DISCOUNT_CODES_DB.get(code_upper)
    if not discount:
        raise DiscountError(
            f"Discount code '{code_upper}' not found.",
            {"code": code_upper}
        )

    # Check if code is active
    if not discount.active:
        raise DiscountError(
            f"Discount code '{code_upper}' is no longer active.",
            {"code": code_upper}
        )

    # Check admin-only restriction
    if discount.admin_only and not user.is_admin:
        raise DiscountError(
            f"Discount code '{code_upper}' is restricted to admin users only.",
            {"code": code_upper, "user_tier": user.tier.value, "required": "admin"}
        )

    # Check user tier permission
    if user.tier not in discount.allowed_tiers:
        allowed_tier_names = [t.value for t in discount.allowed_tiers]
        raise DiscountError(
            f"User tier '{user.tier.value}' is not eligible for discount code '{code_upper}'. "
            f"Allowed tiers: {allowed_tier_names}",
            {
                "code": code_upper,
                "user_tier": user.tier.value,
                "allowed_tiers": allowed_tier_names,
            }
        )

    # Check minimum order amount
    if subtotal < discount.min_order_amount:
        raise DiscountError(
            f"Order subtotal (${subtotal:.2f}) does not meet minimum amount "
            f"(${discount.min_order_amount:.2f}) for code '{code_upper}'.",
            {
                "code": code_upper,
                "subtotal": subtotal,
                "min_required": discount.min_order_amount,
            }
        )

    # Calculate discount
    discount_amount = round(subtotal * (discount.percentage / 100.0), 2)

    # Apply max discount cap if set
    if discount.max_discount_amount is not None:
        discount_amount = min(discount_amount, discount.max_discount_amount)

    discounted_subtotal = round(subtotal - discount_amount, 2)

    result = DiscountResult(
        original_subtotal=subtotal,
        discount_amount=discount_amount,
        discounted_subtotal=discounted_subtotal,
        discount_code_applied=code_upper,
        discount_message=f"Discount code '{code_upper}' applied: {discount.percentage}% off "
                         f"(saved ${discount_amount:.2f})",
    )

    print(f"[Step 2] {result.discount_message}")
    print(f"  Subtotal: ${subtotal:.2f} -> ${discounted_subtotal:.2f}")

    return result


def step3_calculate_tax(
    discount_result: DiscountResult,
    tax_info: TaxInfo,
) -> TaxResult:
    """Step 3: Calculate tax based on location and discounted subtotal."""
    subtotal_after_discount = discount_result.discounted_subtotal
    state = tax_info.state.upper().strip()

    # Look up tax rate
    if state not in TAX_RATES_DB:
        # Use provided tax rate if state not in DB, but validate it
        if tax_info.tax_rate < 0 or tax_info.tax_rate > 0.25:
            raise TaxCalculationError(
                f"Invalid tax rate: {tax_info.tax_rate}. Must be between 0 and 0.25 (25%).",
                {"state": state, "tax_rate": tax_info.tax_rate}
            )
        tax_rate = tax_info.tax_rate
    else:
        tax_rate = TAX_RATES_DB[state]

    tax_amount = round(subtotal_after_discount * tax_rate, 2)
    total_with_tax = round(subtotal_after_discount + tax_amount, 2)

    result = TaxResult(
        subtotal_after_discount=subtotal_after_discount,
        tax_amount=tax_amount,
        tax_rate=tax_rate,
        total_with_tax=total_with_tax,
        state=state,
    )

    print(f"[Step 3] Tax calculated for state '{state}': rate={tax_rate*100:.2f}%, "
          f"tax=${tax_amount:.2f}")
    print(f"  Total with tax: ${total_with_tax:.2f}")

    return result


